import { Fragment, useMemo, useState } from 'react'
import { useRuns } from '../hooks/useRuns'
import { useChangeStream } from '../hooks/useChangeStream'
import { SlideOver } from '../components/SlideOver'
import type { JobRun } from '../backend-types/JobRun'
import type { JobSpec } from '../backend-types/JobSpec'
import { RunDetail } from './RunDetail'
import { useJobs } from '../hooks/useJobs'
import type { ListRunsQuery } from '../backend-types'
import { SearchableDropdown } from '../components/SearchableDropdown'
import { useWorkers } from '../hooks/useWorkers'
import {
  Listbox,
  ListboxButton,
  ListboxOption,
  ListboxOptions,
  Transition,
} from '@headlessui/react'

const POLL_OPTIONS = [
  { ms: 0, label: 'Live', desc: 'Push (SSE)' },
  { ms: 200, label: '0.2s', desc: 'Spammy' },
  { ms: 1000, label: '  1s', desc: 'Fast' },
  { ms: 2000, label: '  2s', desc: 'Normal' },
  { ms: 10000, label: ' 10s', desc: 'Chill' },
]

export function PollSelect({
  pollMs,
  setPollMs,
}: {
  pollMs: number
  setPollMs: (n: number) => void
}) {
  return (
    <Listbox value={pollMs} onChange={setPollMs}>
      <div className="relative">
        <label className="block text-sm font-medium mb-1 text-(--text-primary)">
          Update Rate
        </label>

        {/* Compact button */}
        <ListboxButton
          className="
            w-20 text-left font-mono px-2 py-1 rounded border
            bg-(--bg-app) text-(--text-primary)
            border-(--border-color)
            hover:border-(--text-accent)
            focus:outline-none focus:ring-1 focus:ring-(--text-accent)
          "
        >
          {POLL_OPTIONS.find((p) => p.ms === pollMs)?.label ?? 'Select'}
        </ListboxButton>

        {/* Dropdown */}
        <Transition
          as={Fragment}
          enter="transition ease-out duration-100"
          enterFrom="opacity-0 scale-95"
          enterTo="opacity-100 scale-100"
          leave="transition ease-in duration-75"
          leaveFrom="opacity-100 scale-100"
          leaveTo="opacity-0 scale-95"
        >
          <ListboxOptions
            className="
             absolute mt-1 z-20 min-w-max w-48 py-1 rounded shadow
             bg-(--bg-popover)
             border border-(--border-color)
           "
          >
            {POLL_OPTIONS.map((opt) => (
              <ListboxOption
                key={opt.ms}
                value={opt.ms}
                className="
                  cursor-pointer select-none px-3 py-2 font-mono flex gap-4
                  text-(--text-primary)
                  data-[headlessui-state~=active]:bg-(--bg-popover-hover)
                "
              >
                <span className="w-12 text-right">{opt.label}</span>
                <span className="text-(--text-secondary) whitespace-nowrap">
                  {opt.desc}
                </span>
              </ListboxOption>
            ))}
          </ListboxOptions>
        </Transition>
      </div>
    </Listbox>
  )
}

const PAGE = 100

export function RunsPage() {
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const [filterJobId, setFilterJobId] = useState<string | undefined>(undefined)
  const [filterWorkerId, setFilterWorkerId] = useState<string | undefined>(
    undefined
  )
  const [pollMs, setPollMs] = useState(0)
  const [limit, setLimit] = useState(PAGE)
  const [groupByJob, setGroupByJob] = useState(false)

  // Live by default: the runs change-stream invalidates run queries on change, so the list
  // updates without a fixed poll. The poll selector remains as an optional periodic refetch.
  useChangeStream('/api/v1/runs/stream', 'runs')

  // "Load more" grows the window rather than accumulating pages, so polling keeps every
  // shown run's state live (a queued -> running -> succeeded transition is reflected).
  // TODO: true incremental polling (fetch only new/changed) needs an updated_at cursor.

  const makeQuery = () => {
    const q: ListRunsQuery = {}
    if (filterJobId) {
      q.byJobId = filterJobId
    }
    if (filterWorkerId) {
      q.byWorkerId = filterWorkerId
    }

    q.limit = limit

    return q
  }
  const {
    data: runs,
    isLoading,
    error,
    refetch: refetchRuns,
  } = useRuns(makeQuery(), pollMs)
  const { data: jobs, error: jobsError } = useJobs()
  const { data: workers, error: workersError } = useWorkers()

  const getSelected = () => runs?.find((r) => r.id === selectedId) ?? null
  // const getJob = (job_id: string) => jobs?.find((job) => job.id === job_id)

  const jobsMap = useMemo(() => {
    const m = new Map<string, JobSpec>()
    jobs?.forEach((j) => m.set(j.id, j))
    return m
  }, [jobs])

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-semibold">Recent Runs</h2>

      {isLoading && <p className="text-(--text-muted)">Loading…</p>}
      {error && <p className="text-(--text-danger)">{String(error)}</p>}
      {jobsError && <p className="text-(--text-danger)">{String(jobsError)}</p>}
      {workersError && (
        <p className="text-(--text-danger)">{String(workersError)}</p>
      )}

      <div className="flex gap-4 items-end">
        {/* Job filter */}
        <SearchableDropdown
          label="Job"
          items={[
            { value: '', label: '- All jobs -' },
            ...(jobs?.map((j) => ({ value: j.id, label: j.name })) ?? []),
          ]}
          value={filterJobId ?? ''}
          onChange={(val) => setFilterJobId(val || undefined)}
        />
        {/* Worker filter */}
        <SearchableDropdown
          label="Worker"
          items={[
            { value: '', label: '- All workers -' },
            ...(workers?.map((w) => ({
              value: w.id,
              label: `${w.hostname}-${w.id}`,
            })) ?? []),
          ]}
          value={filterWorkerId ?? ''}
          onChange={(val) => setFilterWorkerId(val || undefined)}
        />

        {/* Polling Frequency */}
        <div>
          <div className="flex gap-2 items-end">
            <PollSelect pollMs={pollMs} setPollMs={setPollMs} />
            {pollMs === 0 && (
              <button
                type="button"
                onClick={() => refetchRuns()}
                className="
                  px-3 py-2 rounded text-sm font-medium
                  bg-(--bg-btn-secondary) text-(--text-primary)
                  border border-(--border-subtle)
                  hover:bg-(--bg-btn-secondary-hover)
                  transition
                "
              >
                Refresh Now
              </button>
            )}
          </div>
        </div>

        {/* Group by job */}
        <label className="flex items-center gap-2 text-sm text-(--text-primary) pb-2">
          <input
            type="checkbox"
            checked={groupByJob}
            onChange={(e) => setGroupByJob(e.target.checked)}
          />
          Group by job
        </label>
      </div>

      {runs &&
        (groupByJob ? (
          <GroupedRuns runs={runs} jobsMap={jobsMap} onSelect={setSelectedId} />
        ) : (
          <RunsTable runs={runs} jobsMap={jobsMap} onSelect={setSelectedId} showJob />
        ))}

      {runs && runs.length >= limit && (
        <button
          type="button"
          onClick={() => setLimit((l) => l + PAGE)}
          className="
            px-4 py-2 rounded text-sm font-medium
            bg-(--bg-btn-secondary) text-(--text-primary)
            border border-(--border-subtle)
            hover:bg-(--bg-btn-secondary-hover)
          "
        >
          Load more
        </button>
      )}

      <SlideOver
        open={!!getSelected()}
        onClose={() => setSelectedId(null)}
        title={`Run ${getSelected()?.id}`}
      >
        {getSelected() && <RunDetail run={getSelected()!} />}
      </SlideOver>
    </div>
  )
}

function RunsTable({
  runs,
  jobsMap,
  onSelect,
  showJob = false,
}: {
  runs: JobRun[]
  jobsMap: Map<string, JobSpec>
  onSelect: (id: string) => void
  showJob?: boolean
}) {
  return (
    <div className="rounded-lg shadow border border-(--border-color) overflow-hidden bg-(--bg-surface-alt)">
      <table className="w-full text-left">
        <thead className="bg-(--bg-header) border-b border-(--border-subtle)">
          <tr>
            {showJob && <th className="px-4 py-2 font-semibold">Job</th>}
            <th className="px-4 py-2 font-semibold">State</th>
            <th className="px-4 py-2 font-semibold">Started</th>
            <th className="px-4 py-2 font-semibold">Finished</th>
            <th className="px-4 py-2 font-semibold">Scheduled for</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-(--border-subtle)">
          {runs.map((run) => (
            <tr
              key={run.id}
              className="hover:bg-(--bg-row-hover) cursor-pointer"
              onClick={() => onSelect(run.id)}
            >
              {showJob && (
                <td className="px-4 py-2">
                  <div>
                    <span>{jobsMap.get(run.jobId)?.name ?? '<Unknown Job>'}</span>
                    <div className="text-xs text-(--text-muted)">
                      Worker: {run.workerId ?? '—'}
                    </div>
                  </div>
                </td>
              )}
              <td className="px-4 py-2">
                <RunStateBadge state={run.state} runId={run.id} />
              </td>
              <td className="px-4 py-2">{formatTime(run.startedAt)}</td>
              <td className="px-4 py-2">{formatTime(run.finishedAt)}</td>
              <td className="px-4 py-2">{formatTime(run.scheduledFor)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

function GroupedRuns({
  runs,
  jobsMap,
  onSelect,
}: {
  runs: JobRun[]
  jobsMap: Map<string, JobSpec>
  onSelect: (id: string) => void
}) {
  const groups = useMemo(() => {
    const m = new Map<string, JobRun[]>()
    for (const r of runs) {
      const arr = m.get(r.jobId) ?? []
      arr.push(r)
      m.set(r.jobId, arr)
    }
    const name = (id: string) => jobsMap.get(id)?.name ?? id
    return [...m.entries()].sort((a, b) => name(a[0]).localeCompare(name(b[0])))
  }, [runs, jobsMap])

  return (
    <div className="space-y-6">
      {groups.map(([jobId, jobRuns]) => (
        <div key={jobId} className="space-y-2">
          <h3 className="text-sm font-semibold text-(--text-primary)">
            {jobsMap.get(jobId)?.name ?? '<Unknown Job>'}{' '}
            <span className="text-(--text-muted) font-normal">
              ({jobRuns.length})
            </span>
          </h3>
          <RunsTable runs={jobRuns} jobsMap={jobsMap} onSelect={onSelect} />
        </div>
      ))}
    </div>
  )
}

function formatTime(t?: string | null) {
  if (!t) return '—'
  return new Date(t).toLocaleString()
}

